+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown') {
+      text = convertWikiLinks(text, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = convertMarkdownLinks(text, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = convertWikiLinks(text, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = convertMarkdownLinks(text, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Converts wiki links and embeds to markdown',
+        before: '[[Page#Heading]] and ![[image.png|300x200]]',
+        after: '[Page > Heading](Page#Heading) and ![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Converts inline markdown links and images to wiki syntax',
+        before: '[Display](Page) and ![alt](image.png)',
+        after: '[[Page|Display]] and ![[image.png|alt]]',
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: styleRecords(),
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records: styleRecords(),
+      }),
+    ];
+  }
+}
+
+function styleRecords(): {value: LinkStyleValue, description: string}[] {
+  return [
+    {value: 'no-change', description: 'Leaves this kind of link unchanged'},
+    {value: 'markdown', description: 'Uses standard markdown syntax'},
+    {value: 'wiki', description: 'Uses Obsidian wiki link syntax'},
+  ];
+}
+
+function convertWikiLinks(text: string, image: boolean): string {
+  const prefix = image ? '![["' : '[["';
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const start = text.indexOf(prefix, index);
+    if (start === -1) return result + text.slice(index);
+    result += text.slice(index, start);
+    const end = text.indexOf(']]', start + prefix.length);
+    if (end === -1) return result + text.slice(start);
+
+    const content = text.slice(start + prefix.length, end);
+    if (content.includes('\
')) {
+      result += text.slice(start, end + 2);
+    } else {
+      const separator = content.indexOf('|');
+      const target = separator === -1 ? content : content.slice(0, separator);
+      let display = separator === -1 ? target : content.slice(separator + 1);
+      if (image && /^(?:\\d+|\\d+x\\d+)$/.test(display)) display = '';
+      if (!image && display === target) display = defaultHeadingDisplay(target);
+      result += image ? `![${display}](${target})` : `[${display}](${target})`;
+    }
+    index = end + 2;
+  }
+  return result;
+}
+
+function convertMarkdownLinks(text: string, image: boolean): string {
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const start = findMarkdownStart(text, index, image);
+    if (start === -1) return result + text.slice(index);
+    result += text.slice(index, start);
+    const parsed = parseMarkdownLink(text, start, image);
+    if (!parsed) {
+      result += text[start];
+      index = start + 1;
+      continue;
+    }
+    const {end, label, target} = parsed;
+    if (target.includes('://')) {
+      result += text.slice(start, end);
+    } else if (image) {
+      result += `![[${target}${label === '' || label === target ? '' : `|${label}`}]]`;
+    } else {
+      const defaultDisplay = defaultHeadingDisplay(target);
+      result += `[[${target}${label === target || label === defaultDisplay ? '' : `|${label}`}]]`;
+    }
+    index = end;
+  }
+  return result;
+}
+
+function findMarkdownStart(text: string, from: number, image: boolean): number {
+  for (let index = from; index < text.length; index++) {
+    if (image) {
+      if (text[index] === '!' && text[index + 1] === '[' && !isEscaped(text, index)) return index;
+    } else if (text[index] === '[' && text[index - 1] !== '!' && !isEscaped(text, index)) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseMarkdownLink(text: string, start: number, image: boolean): {end: number, label: string, target: string} | null {
+  const labelStart = start + (image ? 2 : 1);
+  let depth = 1;
+  let index = labelStart;
+  for (; index < text.length; index++) {
+    if (text[index] === '\
') return null;
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '[') depth++;
+    if (text[index] === ']' && --depth === 0) break;
+  }
+  if (depth !== 0 || text[index + 1] !== '(') return null;
+
+  const destinationStart = index + 2;
+  const destinationEnd = findDestinationEnd(text, destinationStart);
+  if (destinationEnd === -1) return null;
+  const destination = parseDestination(text.slice(destinationStart, destinationEnd));
+  if (destination === null) return null;
+  return {end: destinationEnd + 1, label: unescapeMarkdown(text.slice(labelStart, index)), target: destination};
+}
+
+function findDestinationEnd(text: string, start: number): number {
+  let depth = 1;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\
') return -1;
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '(') depth++;
+    if (text[index] === ')' && --depth === 0) return index;
+  }
+  return -1;
+}
+
+function parseDestination(value: string): string | null {
+  if (value.includes('\
')) return null;
+  const trimmed = value.trim();
+  if (trimmed.startsWith('<')) {
+    const close = findUnescaped(trimmed, '>', 1);
+    if (close === -1 || trimmed.slice(close + 1).trim() !== '') return null;
+    return unescapeMarkdown(trimmed.slice(1, close));
+  }
+  if (trimmed === '' || /(?<!\\\\)\\s/.test(trimmed)) return null;
+  return unescapeMarkdown(trimmed);
+}
+
+function findUnescaped(text: string, character: string, from: number): number {
+  for (let index = from; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === character) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function isEscaped(text: string, index: number): boolean {
+  let count = 0;
+  for (let current = index - 1; current >= 0 && text[current] === '\\\'; current--) count++;
+  return count % 2 === 1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) return target;
+  const page = target.slice(0, hash);
+  const heading = target.slice(hash + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
